import psycopg2

def install_extension(connection_string, extension_name):
    try:
        # Connect to the PostgreSQL server
        conn = psycopg2.connect(connection_string)
        cursor = conn.cursor()

        # Create the extension
        create_extension_query = "CREATE EXTENSION IF NOT EXISTS {}".format(extension_name)
        cursor.execute(create_extension_query)

        # Commit the transaction
        conn.commit()
        print(f"Extension '{extension_name}' installed successfully.")

    except psycopg2.Error as e:
        print(f"Error installing extension: {e}")

    finally:
        # Close communication with the database
        if cursor:
            cursor.close()
        if conn:
            conn.close()

if __name__ == "__main__":
    # Example connection string, replace with your actual connection details
    connection_string = "dbname='your_dbname' user='your_user' host='localhost' password='your_password'"
    
    # Get extension name from user input
    extension_name = input("Enter the name of the PostgreSQL extension to install: ")
    
    # Install the specified extension
